p[2] = 2; // Base case: 2 ways to reach step 2\n\n// Fill DP table\nfor (let i = 3; i <= N; i++) {\n  // To reach step i, can come from step i-1 (1 step) or step i-2 (2 steps)\n  dp[i] = dp[i - 1] + dp[i - 2];\n}\n\nreturn dp[N];\n}\n\n// Test cases\nconsole.log('Example 1:', climbStairs(2)); \n// 2\n\nconsole.log('Example 2:', climbStairs(3)); \n// 3\n\nconsole.log('Example 3:', climbStairs(4)); \n// 5\n\nconsole.log('Example 4:', climbStairs(1)); \n// 1",testCases:[{input:"climbStairs(2)",expected:"2"},{input:"climbStairs(3)",expected:"3"},{input:"climbStairs(4)",expected:"5"},{input:"climbStairs(1)",expected:"1"}]})}),(0,r.jsx)(l.A,{value:"python",label:"Python Solution",children:(0,r.jsx)(o.A,{language:"python",title:"Python Solution - Dynamic Programming",code:"def climb_stairs(N: int) -> int:\n  \"\"\"\n  Count ways to climb N steps (1 or 2 steps at a time)\n  \n  Args:\n      N: Number of steps\n      \n  Returns:\n      int: Total number of ways\n  \"\"\"\n  if N <= 1:\n      return 1\n  if N == 2:\n      return 2\n  \n  # dp[i] = number of ways to reach step i\n  dp = [0] * (N + 1)\n  dp[0] = 1  # Base case: 1 way to be at ground (start)\n  dp[1] = 1  # Base case: 1 way to reach step 1\n  dp[2] = 2  # Base case: 2 ways to reach step 2\n  \n  # Fill DP table\n  for i in range(3, N + 1):\n      # To reach step i, can come from step i-1 (1 step) or step i-2 (2 steps)\n      dp[i] = dp[i - 1] + dp[i - 2]\n  \n  return dp[N]\n\n# Test cases\nprint('Example 1:', climb_stairs(2))  \n# 2\n\nprint('Example 2:', climb_stairs(3))  \n# 3\n\nprint('Example 3:', climb_stairs(4))  \n# 5\n\nprint('Example 4:', climb_stairs(1))  \n# 1",testCases:[{input:"climb_stairs(2)",expected:"2"},{input:"climb_stairs(3)",expected:"3"},{input:"climb_stairs(4)",expected:"5"},{input:"climb_stairs(1)",expected:"1"}]})})]}),"\n",(0,r.jsx)(n.h2,{id:"alternative-solution-space-optimized",children:"Alternative Solution (Space-Optimized)"}),"\n",(0,r.jsx)(n.p,{children:"Here's a space-optimized